<svg viewBox="0 0 700 420" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="28" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Drei Modelle Tokenisierter Wertpapiere im Vergleich</text>
  <text x="20" y="48" fill="#71717a" font-size="13" font-family="sans-serif">STA bittet SEC, das emittentengestützte Modell zu bevorzugen</text>
  <rect x="25" y="75" width="205" height="195" rx="8" fill="#18181b" stroke="#4ade80" stroke-width="1.5"/>
  <text x="127" y="100" fill="#86efac" font-size="14" font-weight="700" font-family="sans-serif" text-anchor="middle">Emittentengestützt</text>
  <text x="40" y="128" fill="#d4d4d8" font-size="13" font-family="sans-serif">Eigentum: direkt</text>
  <text x="40" y="153" fill="#d4d4d8" font-size="13" font-family="sans-serif">Aktionärsregister: gelistet</text>
  <text x="40" y="178" fill="#d4d4d8" font-size="13" font-family="sans-serif">Kernrisiko: niedrig</text>
  <text x="40" y="240" fill="#71717a" font-size="12" font-family="sans-serif">Bsp: Securitize SECZ</text>
  <rect x="247" y="75" width="205" height="195" rx="8" fill="#18181b" stroke="#fbbf24" stroke-width="1.5"/>
  <text x="349" y="100" fill="#fde68a" font-size="14" font-weight="700" font-family="sans-serif" text-anchor="middle">Custodial (Dritter)</text>
  <text x="262" y="128" fill="#d4d4d8" font-size="13" font-family="sans-serif">Eigentum: indirekter Anspruch</text>
  <text x="262" y="153" fill="#d4d4d8" font-size="13" font-family="sans-serif">Aktionärsregister: nicht gelistet</text>
  <text x="262" y="178" fill="#d4d4d8" font-size="13" font-family="sans-serif">Kernrisiko: Verwahrung/Kontrahent</text>
  <text x="262" y="240" fill="#71717a" font-size="12" font-family="sans-serif">Bsp: Ondo IVV/Micron</text>
  <rect x="469" y="75" width="205" height="195" rx="8" fill="#18181b" stroke="#f87171" stroke-width="1.5"/>
  <text x="571" y="100" fill="#fecaca" font-size="14" font-weight="700" font-family="sans-serif" text-anchor="middle">Synthetic (Dritter)</text>
  <text x="484" y="128" fill="#d4d4d8" font-size="13" font-family="sans-serif">Eigentum: keins (nur wirtschaftlich)</text>
  <text x="484" y="153" fill="#d4d4d8" font-size="13" font-family="sans-serif">Aktionärsregister: nicht gelistet</text>
  <text x="484" y="178" fill="#d4d4d8" font-size="13" font-family="sans-serif">Kernrisiko: Emittenten-Insolvenz</text>
